export const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"] as const;

export const SCRIPT_TYPE = (() => {
	if (typeof window === "undefined" || window.location.href.endsWith("/_generated_background_page.html")) {
		return "BACKGROUND";
	} else if (typeof browser === "object" && browser.action) {
		return "POPUP";
		// } else if (!chrome?.runtime?.onMessage) {
		// return "WEB";
	} else {
		return "CONTENT";
	}
})();

export function arraysEquals(a1: unknown[], a2: unknown[]) {
	if (a1.length !== a2.length) return false;

	for (let i = 0; i < a1.length; i++) {
		const x1 = a1[i];
		const x2 = a2[i];
		if (Array.isArray(x1) && Array.isArray(x2)) {
			if (!arraysEquals(x1, x2)) return false;
		} else if (typeof x1 === "object" && typeof x2 === "object") {
			if (!objectsEquals(x1 as object, x2 as object)) return false;
		} else if (x1 !== x2) {
			return false;
		}
	}
	return true;
}

export function objectsEquals(o1: object, o2: object) {
	for (const property in o1) {
		if (Object.hasOwn(o1, property) !== Object.hasOwn(o2, property)) return false;
		else if (typeof o1[property] !== typeof o2[property]) return false;
	}
	for (const property in o2) {
		if (Object.hasOwn(o1, property) !== Object.hasOwn(o2, property)) return false;
		else if (typeof o1[property] !== typeof o2[property]) return false;

		if (!Object.hasOwn(o1, property)) continue;

		const x1 = o1[property];
		const x2 = o2[property];

		if (Array.isArray(x1) && Array.isArray(x2)) {
			if (!arraysEquals(x1, x2)) return false;
		} else if (typeof x1 === "object" && typeof x2 === "object") {
			if (!objectsEquals(x1, x2)) return false;
		} else if (x1 !== x2) return false;
	}

	return true;
}

export function sleep(millis: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, millis));
}

export const TO_MILLIS = {
	SECONDS: 1000,
	MINUTES: 1000 * 60,
	HOURS: 1000 * 60 * 60,
	DAYS: 1000 * 60 * 60 * 24,
} as const;

export function findItemInObject<T>(object: { [key: string | number]: T }, attributes: object = {}): undefined | (T & { id: string }) {
	if (!object || Object.keys(attributes).length === 0) return undefined;

	for (const id in object) {
		const item = {
			id,
			...object[id],
		};
		if (!Object.keys(attributes).every((attribute) => item[attribute] === attributes[attribute])) continue;

		return item;
	}

	return undefined;
}

export function findItemInList<T>(list: T[], attributes: object = {}): undefined | T {
	if (!list || list.length === 0) return undefined;

	for (const item of list) {
		if (!Object.keys(attributes).every((attribute) => item[attribute] === attributes[attribute])) continue;

		return item;
	}

	return undefined;
}

export function isIntNumber(number: string | null): boolean {
	if (number === null) return false;
	if (number.match(/[a-zA-Z]/)) return false;

	const _number = parseFloat(number.toString());
	return !Number.isNaN(_number) && Number.isFinite(_number) && _number % 1 === 0;
}

export function isSameUTCDay(date1: number | string | Date, date2: number | string | Date) {
	const _date1 = new Date(date1);
	const _date2 = new Date(date2);

	return _date1.setUTCHours(24, 0, 0, 0) === _date2.setUTCHours(24, 0, 0, 0);
}

export function getUTCTodayAtTime(hours: number, minutes: number) {
	const date = new Date();
	date.setUTCHours(hours, minutes);

	return date;
}

export function isToday(timestamp: number) {
	return new Date().getDate() === new Date(timestamp).getDate();
}

export function hasTimePassed(timestamp: number, time: number) {
	const difference = Date.now() - timestamp;

	return Math.abs(difference) >= time;
}

export function getUUID() {
	return `_${Math.random().toString(36).substr(2, 9)}`;
}

export function getCookie(cname: string) {
	const name = `${cname}=`;

	for (let cookie of decodeURIComponent(document.cookie).split(";")) {
		cookie = cookie.trimStart();

		if (cookie.includes(name)) {
			return cookie.substring(name.length);
		}
	}
	return "";
}

export function getValue(x: any) {
	return typeof x === "function" ? x() : x;
}

export async function getValueAsync<T>(x: () => T | Promise<T>): Promise<T> {
	if (x.constructor.name === "AsyncFunction") return x();
	else {
		const value = x();

		if (value instanceof Promise) return value;
		else return value;
	}
}

export function toCorrectType(object: { [key: string]: any }) {
	object = { ...object };

	for (const key in object) {
		const value = object[key];
		if (!Number.isNaN(value)) object[key] = parseFloat(value);
		else if (value === "true") object[key] = true;
		else if (value === "false") object[key] = false;
	}

	return object;
}

export function toClipboard(text: string) {
	if (navigator?.clipboard?.writeText) {
		navigator.clipboard.writeText(text).then(() => {});
		return true;
	} else {
		const textarea = elementBuilder({ type: "textarea", value: text, style: { position: "absolute", left: "-9999px" }, attributes: { readonly: "" } });
		document.body.appendChild(textarea);

		textarea.select();
		const copied = document.execCommand("copy");

		document.body.removeChild(textarea);
		return copied;
	}
}

export function getTimeUntilNextJobUpdate() {
	const now = Date.now();

	const nextJobUpdate = new Date();
	nextJobUpdate.setUTCHours(18);
	nextJobUpdate.setUTCMinutes(30);
	nextJobUpdate.setUTCSeconds(0);
	nextJobUpdate.setUTCMilliseconds(0);

	// If the current time is after 6:30 PM, add 1 day to the target time
	if (nextJobUpdate.getTime() <= now) {
		nextJobUpdate.setDate(nextJobUpdate.getDate() + 1);
	}

	return nextJobUpdate.getTime() - now;
}

export function toNumericVersion(version: string) {
	return parseInt(
		version
			.split(".")
			.map((part) => part.padStart(3, "0"))
			.join("")
			.padEnd(9, "9"),
	);
}

export function calculateDatePeriod(startDate: Date, endDate: Date) {
	// Ensure endDate is not before startDate
	if (startDate > endDate) {
		[startDate, endDate] = [endDate, startDate]; // Swap if dates are in wrong order
	}

	// Create mutable copies of the dates to avoid modifying the originals
	const currentStartDate = new Date(startDate.getTime());
	const currentEndDate = new Date(endDate.getTime());

	// Increment years until adding another year would exceed the end date
	let years = 0;
	while (
		currentStartDate.getFullYear() + 1 <= currentEndDate.getFullYear() ||
		(currentStartDate.getFullYear() + 1 === currentEndDate.getFullYear() &&
			(currentStartDate.getMonth() < currentEndDate.getMonth() ||
				(currentStartDate.getMonth() === currentEndDate.getMonth() && currentStartDate.getDate() <= currentEndDate.getDate())))
	) {
		currentStartDate.setFullYear(currentStartDate.getFullYear() + 1);
		years++;
	}

	// Adjust currentStartDate back by one year if it overshot
	if (currentStartDate > currentEndDate && years > 0) {
		currentStartDate.setFullYear(currentStartDate.getFullYear() - 1);
		years--;
	}

	// Increment months until adding another month would exceed the end date
	let months = 0;
	while (currentStartDate.getMonth() < 11 || currentStartDate.getFullYear() < currentEndDate.getFullYear()) {
		const testDate = new Date(currentStartDate.getTime());
		testDate.setMonth(testDate.getMonth() + 1);

		if (testDate > currentEndDate) {
			break;
		}
		currentStartDate.setMonth(currentStartDate.getMonth() + 1);
		months++;
	}

	// Calculate days
	// The difference in milliseconds between the remaining dates
	const diffTime = Math.abs(currentEndDate.getTime() - currentStartDate.getTime());
	// Convert milliseconds to days
	const days = Math.floor(diffTime / (1000 * 60 * 60 * 24));

	return { years, months, days };
}

export function toRecord<TItem, TValue, TKey extends string = string>(
	array: TItem[],
	fn: (item: TItem, index: number) => [TKey, TValue],
): Record<TKey, TValue> {
	return array.reduce<Record<TKey, TValue>>(
		(record, item, index) => {
			const [key, value] = fn(item, index);
			record[key] = value;

			return record;
		},
		{} as Record<TKey, TValue>,
	);
}

export function groupBy<TItem, TValue>(array: TItem[], fn: (item: TItem, index: number) => [string, TValue]): Record<string, TValue[]> {
	return array.reduce<Record<string, TValue[]>>((record, item, index) => {
		const [key, value] = fn(item, index);
		record[key] = record[key] ?? [];
		record[key].push(value);

		return record;
	}, {});
}

/**
 * Like keyof but for keys with specific value.
 *
 * For example: `TypedKeyOf<{a: number; b: string}, string>` will yield `'b'`
 */
export type TypedKeyOf<T, K> = { [P in keyof T]: T[P] extends K ? P : never }[keyof T];

export function getTypedKeyOf<T, K>(item: T, typedKeyOf: TypedKeyOf<T, K>): K {
	return item[typedKeyOf] as K;
}

export function isTabFocused() {
	return document.hasFocus();
}

export function isNumber(x: any): x is number {
	return typeof x === "number";
}
